        AND nx_pr_paper_type = #{paperType}


        AND nx_pr_print_status = #{printStatus}


        AND DATE(nx_pr_print_time) >= #{startDate}


        AND DATE(nx_pr_print_time) <= #{stopDate}


ORDER BY nx_pr_print_time DESC

    LIMIT #{offset}, #{limit}

SELECT 
    pr.*,
    d.nx_distributer_name AS distributerName,
    dev.nx_pd_device_name AS deviceName,
    dev.nx_pd_device_no AS deviceNo
FROM nx_machine_print_record pr
LEFT JOIN nx_distributer d ON pr.nx_pr_distributer_id = d.nx_distributer_id
LEFT JOIN nx_machine_printer_device dev ON pr.nx_pr_device_id = dev.nx_pd_id


        AND pr.nx_pr_market_id = #{marketId}


        AND pr.nx_pr_device_id = #{deviceId}


        AND pr.nx_pr_distributer_id = #{distributerId}


        AND pr.nx_pr_bill_id = #{billId}


        AND pr.nx_pr_paper_type = #{paperType}


        AND pr.nx_pr_print_status = #{printStatus}


        AND DATE(pr.nx_pr_print_time) >= #{startDate}


        AND DATE(pr.nx_pr_print_time) <= #{stopDate}


ORDER BY pr.nx_pr_print_time DESC

    LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM nx_machine_print_record


        AND nx_pr_market_id = #{marketId}


        AND nx_pr_device_id = #{deviceId}


        AND nx_pr_distributer_id = #{distributerId}


        AND nx_pr_bill_id = #{billId}


