        AND DATE(nx_pr_print_time) >= #{startDate}


        AND DATE(nx_pr_print_time) <= #{stopDate}

mapper.update:
UPDATE nx_machine_print_record
nx_pr_print_status = #{nxPrPrintStatus}, nx_pr_remark = #{nxPrRemark},
WHERE nx_pr_id = #{nxPrId}

mapper.select:
SELECT * FROM nx_machine_print_record 
WHERE nx_pr_bill_id = #{billId}
ORDER BY nx_pr_print_time DESC

SELECT DATE_FORMAT(nx_pr_print_time, '%Y-%m-%d') AS print_date, COUNT(*) AS print_count, SUM(nx_pr_paper_count) AS total_paper, -- 只统计配送商状态=0（正式）的打印费用，体验打印不计入市场收入 SUM(CASE WHEN nx_pr_distributer_type = 0 THEN nx_pr_bill_total ELSE 0 END) AS total_amount FROM nx_machine_print_record
nx_pr_print_status = 1
AND nx_pr_market_id = #{marketId}
AND nx_pr_device_id = #{deviceId}
AND DATE(nx_pr_print_time) >= #{startDate}
AND DATE(nx_pr_print_time) <= #{stopDate}
GROUP BY DATE_FORMAT(nx_pr_print_time, '%Y-%m-%d') ORDER BY print_date DESC

SELECT pr.nx_pr_device_id AS device_id, pd.nx_pd_device_name AS device_name, pd.nx_pd_device_no AS device_no, pd.nx_pd_model AS device_model, pd.nx_pd_location AS device_location, pd.nx_pd_paper_type AS paper_type, pd.nx_pd_paper_count AS current_paper_count, pd.nx_pd_paper_max AS paper_max, pd.nx_pd_status AS device_status, COUNT(*) AS print_count, SUM(pr.nx_pr_paper_count) AS total_paper_used, -- 只统计配送商状态=0（正式）的打印费用，体验打印不计入市场收入 SUM(CASE WHEN pr.nx_pr_distributer_type = 0 THEN pr.nx_pr_bill_total ELSE 0 END) AS total_amount, DATE_FORMAT(MIN(pr.nx_pr_print_time), '%Y-%m-%d') AS first_print_date, DATE_FORMAT(MAX(pr.nx_pr_print_time), '%Y-%m-%d') AS last_print_date, COUNT(DISTINCT DATE(pr.nx_pr_print_time)) AS active_days, ROUND(COUNT(*) / COUNT(DISTINCT DATE(pr.nx_pr_print_time)), 2) AS avg_daily_count FROM nx_machine_print_record pr LEFT JOIN nx_machine_printer_device pd ON pr.nx_pr_device_id = pd.nx_pd_id
pr.nx_pr_print_status = 1
AND pr.nx_pr_market_id = #{marketId}
AND DATE(pr.nx_pr_print_time) >= #{startDate}
AND DATE(pr.nx_pr_print_time) <= #{stopDate}
GROUP BY pr.nx_pr_device_id, pd.nx_pd_device_name, pd.nx_pd_device_no, pd.nx_pd_model, pd.nx_pd_location, pd.nx_pd_paper_type, pd.nx_pd_paper_count, pd.nx_pd_paper_max, pd.nx_pd_status ORDER BY print_count DESC

SELECT nx_pr_distributer_id AS distributer_id, COUNT(*) AS print_count, SUM(nx_pr_paper_count) AS total_paper, -- 只统计配送商状态=0（正式）的打印费用，体验打印不计入市场收入 SUM(CASE WHEN nx_pr_distributer_type = 0 THEN nx_pr_bill_total ELSE 0 END) AS total_amount FROM nx_machine_print_record
nx_pr_print_status = 1
AND nx_pr_market_id = #{marketId}
AND DATE(nx_pr_print_time) >= #{startDate}
AND DATE(nx_pr_print_time) <= #{stopDate}
GROUP BY nx_pr_distributer_id ORDER BY print_count DESC
